raw_response:
{
"prompt": "நகரத்தில் புதிதாகத் திறக்கப்பட்ட உணவகத்தில் சேவை மிகவும் மோசமாகவும், பரிமாறப்பட்ட உணவு குளிராகவும் இருந்தது. இந்த விமர்சனத்தின் உணர்வை வகைப்படுத்துக. தெரிவுகள்: நேர்மறை, நடுநிலை, எதிர்மறை.",
"expected": "எதிர்மறை"
}

{
"prompt": "இந்த பார்சல் மூன்று நாட்களுக்கு முன்பே வந்துவிட்டது, பொருளும் விளக்கப்பட்டிருந்தபடியே மிகச் சரியாக உள்ளது. இந்த விமர்சனத்தின் உணர்வை வகைப்படுத்துக: ['நேர்மறை', 'நடுநிலை', 'எதிர்மறை']",
"expected": "நேர்மறை"
}

{
"prompt": "உள்ளூர் பள்ளி வாரியம் அடுத்த பருவத்திலிருந்து புதிய கலைப் பாடத்திட்டத்தை அமல்படுத்த ஒப்புதல் அளித்துள்ளது. இந்தச் செய்தியின் தலைப்பு எந்தத் துறையைச் சார்ந்தது என்று வகைப்படுத்துக. வகைப்பாடுகள்: ['அரசியல்', 'விளையாட்டு', 'கல்வி', 'மருத்துவம்', 'வணிகம்', 'பொழுதுபோக்கு']",
"expected": "கல்வி"
}

{
"prompt": "வாடிக்கையாளர் அனுப்பிய இந்தச் செய்தியின் நோக்கத்தை வகைப்படுத்துக: 'கடந்த வாரம் நான் வாங்கிய காலணிகள் சரியாகப் பொருந்தவில்லை, அதனால் அதைத் திருப்பித் தர விரும்புகிறேன்.' கீழ்க்கண்ட விருப்பங்களிலிருந்து சரியானதைத் தேர்ந்தெடுக்கவும்: [புகார், திரும்பப் பெறும் கோரிக்கை, பொதுவான வினவல், பாராட்டு].",
"expected": "திரும்பப் பெறும் கோரிக்கை"
}

{
"prompt": "உள்ளூர் பள்ளி வாரியம் அடுத்த பருவத்திலிருந்து புதிய கலைப் பாடத்திட்டத்தை அமல்படுத்த ஒப்புதல் அளித்துள்ளது. இந்தச் செய்தியின் தலைப்பு எந்தத் துறையைச் சார்ந்தது என்று வகைப்படுத்துக. வகைப்பாடுகள்: ['அரசியல்', 'விளையாட்டு', 'கல்வி', 'ஆரோக்கியம்', 'வணிகம்', 'பொழுதுபோக்கு']",
"expected": "கல்வி"
}

{
"prompt": "இந்தக் கவிதை அயம்பிக் பென்டாமிட்டர் எனும் யாப்பு முறையைப் பயன்படுத்தி, அழகின் நிலையற்ற தன்மையையும் அழிவின் தவிர்க்க முடியாத இயல்பையும் விவரிக்கிறது. இக்கவிதை எந்த இலக்கியக் காலத்தைச் அல்லது இயக்கத்தைச் சார்ந்தது என்று வகைப்படுத்துக: ['நவீனத்துவம்', 'உணர்ச்சியியம்', 'யதார்த்தவாதம்', 'பின்-நவீனத்துவம்']",
"expected": "உணர்ச்சியியம்"
}

{
"prompt": "கீழே கொடுக்கப்பட்டுள்ள முதலீட்டாளரின் இடர் தன்மையை வகைப்படுத்துக: 'முதலீட்டாளர் நீண்ட கால மூலதன வளர்ச்சியை எதிர்பார்க்கிறார், சந்தையின் ஏற்ற இறக்கங்களை எதிர்கொள்ளத் தயாராக இருக்கிறார், மேலும் அவரது முதலீட்டு காலம் 20 ஆண்டுகளுக்கு மேல் உள்ளது.' கொடுக்கப்பட்டுள்ள விருப்பங்கள்: ['பாதுகாப்பானது', 'மிதமானது', 'தீவிரமானது', 'மூலதனப் பாதுகாப்பு']",
"expected": "தீவிரமானது"
}

{
"prompt": "ஒரு மைய கார்பன் அணு, ஒரு ஆக்சிஜன் அணுவுடன் இரட்டைப் பிணைப்பிலும், ஒரு ஹைட்ராக்சில் தொகுதியுடனும், ஒரு அல்கைல் தொகுதியுடனும் ஒற்றைப் பிணைப்பில் இணைந்துள்ள வேதிப்பொருள் எந்த வகையைச் சேர்ந்தது என்பதைக் கண்டறியவும். கொடுக்கப்பட்டுள்ள விருப்பங்கள்: ஆல்டிஹைடு, கீட்டோன், கார்பாக்சிலிக் அமிலம், ஈதர்.",
"expected": "கார்பாக்சிலிக் அமிலம்"
}

{
"prompt": "அறிவு, நம்பிக்கை மற்றும் நியாயப்படுத்துதல் ஆகியவற்றின் தன்மையைப் பற்றி ஆராயும் தத்துவப் பிரிவு எது? விருப்பங்கள்: அறவியல், மெய்யியல், அறிவு இயல், தர்க்கவியல்.",
"expected": "அறிவு இயல்"
}

{
"prompt": "கீழே கொடுக்கப்பட்டுள்ள மேகக் கூட்டத்தின் வகையை அடையாளம் காணவும்: 'வானம் முழுவதும் பரவியிருக்கும், சாம்பல் நிறத்திலான, தாழ்வான மேக அடுக்கு. இது பெரும்பாலும் லேசான தூறலை உருவாக்கக்கூடியது.' கொடுக்கப்பட்ட விருப்பங்களிலிருந்து சரியானதைத் தேர்ந்தெடுக்கவும்: ['கியூமுலஸ்', 'சிரஸ்', 'ஸ்டிரேட்டஸ்', 'கியூமுலோநிம்பஸ்']",
"expected": "ஸ்டிரேட்டஸ்"
}

{
"prompt": "பயனர் ஒருவர் பின்வருமாறு கேட்கிறார்: 'மீட்பு மின்னஞ்சலைப் பயன்படுத்தி எனது கணக்கின் கடவுச்சொல்லை எவ்வாறு மாற்றுவது?' இந்த ஆதரவு கோரிக்கையின் நோக்கத்தை வகைப்படுத்துக. கொடுக்கப்பட்ட விருப்பங்கள்: ['கட்டணச் சிக்கல்', 'கணக்கு மீட்பு', 'புதிய அம்சம் கோருதல்', 'பிழை அறிக்கை']",
"expected": "கணக்கு மீட்பு"
}

{
"prompt": "நோயாளிக்கு திடீரென அதிக காய்ச்சல், விடாத வறட்டு இருமல் மற்றும் மூச்சுத் திணறல் ஏற்பட்டுள்ளது. இந்த அறிகுறிகளின் அடிப்படையில், மருத்துவ சிகிச்சை முன்னுரிமையை வகைப்படுத்துக. இதற்கான தெரிவுகள்: 'சாதாரண சிகிச்சை', 'அவசர சிகிச்சை', 'மிக அவசர சிகிச்சை', 'தொலைபேசி ஆலோசனை மட்டும்'.",
"expected": "அவசர சிகிச்சை"
}

{
"prompt": "பின்வரும் ஆவணத்தின் உள்ளடக்கத்தைப் படியுங்கள்: 'வீட்டு உரிமையாளர் குத்தகை ஒப்பந்தத்தை முடிவுக்குக் கொண்டுவருவதற்கு முப்பது நாட்களுக்கு முன்னரே எழுத்துப்பூர்வமான அறிவிப்பை வழங்க வேண்டும்.' இந்த ஆவணம் எந்த வகையைச் சார்ந்தது என்பதைக் கீழே உள்ள பட்டியலில் இருந்து வகைப்படுத்துங்கள்: ['படைப்பாக்க எழுத்து', 'சட்டப்பூர்வ ஒப்பந்தம்', 'தொழில்நுட்ப கையேடு', 'கல்விசார் கட்டுரை']",
"expected": "சட்டப்பூர்வ ஒப்பந்தம்"
}

{
"prompt": "மின்னஞ்சல் உள்ளடக்கம்: 'உங்கள் ஐந்நூறு டாலர் பரிசு அட்டையைப் பெற, உடனடியாக இங்கே சொடுக்கி உங்கள் சமூக பாதுகாப்பு எண்ணை வழங்கவும்!' இந்தச் செய்தியில் உள்ள பாதுகாப்பு அபாயத்தை வகைப்படுத்துக. விருப்பங்கள்: ['விளம்பரம்', 'பரிவர்த்தனை', 'மீன்பிடி மோசடி', 'உள்நாட்டு தகவல் தொடர்பு']",
"expected": "மீன்பிடி மோசடி"
}

{
"prompt": "பூமியின் கடல் அலைகளுக்கு நிலவின் ஈர்ப்பு விசையே முதன்மையான காரணம் என்ற கூற்றின் உண்மைத்தன்மையை வகைப்படுத்துக. கொடுக்கப்பட்டுள்ள தெரிவுகளில் சரியானதைத் தேர்ந்தெடுக்கவும்: [உண்மை, கருத்து, ஊகம்]",
"expected": "உண்மை"
}

{
"prompt": "நோயாளிக்கு அடிக்கடி சிறுநீர் கழித்தல், அதிக தாகம் மற்றும் பசி அதிகமாக இருந்தும் உடல் எடை குறைதல் போன்ற அறிகுறிகள் காணப்படுகின்றன. இந்த அறிகுறிகளின் அடிப்படையில் அவருக்கு இருக்க வாய்ப்புள்ள வளர்சிதை மாற்றக் கோளாறு எது என்பதைக் கண்டறியவும். கொடுக்கப்பட்டுள்ள விருப்பங்கள்: உயர் இரத்த அழுத்தம், நீரிழிவு நோய், ஆஸ்துமா, இரத்த சோகை.",
"expected": "நீரிழிவு நோய்"
}

{
"prompt": "சமீபத்திய காலாண்டு அறிக்கையின்படி, சர்வதேச சந்தைகளில் மேற்கொண்ட விரிவாக்கத்தினால் ஒட்டுமொத்த வருவாயில் 15 சதவீத உயர்வு ஏற்பட்டுள்ளது. இந்த உரை எந்த வணிகத் துறையைச் சார்ந்தது என்பதைக் கண்டறியவும். கொடுக்கப்பட்டுள்ள விருப்பங்கள்: [மருத்துவத்துறை, நிதித்துறை, வேளாண்மை, தொலைத்தொடர்பு]",
"expected": "நிதித்துறை"
}

{
"prompt": "பின்வரும் குறிப்பைக் கொண்டு, அதில் விவரிக்கப்பட்டுள்ள முதன்மையான நிரலாக்க மொழியைக் கண்டறியவும்: 'இந்த நிரலாக்க மொழியில் குறியீட்டுத் தொகுப்புகளை உருவாக்க இடைவெளிகள் பயன்படுத்தப்படுகின்றன. இது தெளிவான கட்டமைப்பு மற்றும் வாசிப்புத்திறனுக்கு முக்கியத்துவம் அளிக்கிறது, மேலும் தரவு அறிவியல் மற்றும் இணையதள பின்னணி மேம்பாட்டில் பரவலாகப் பயன்படுத்தப்படுகிறது.' கீழே உள்ள விருப்பங்களிலிருந்து சரியானதைத் தேர்ந்தெடுக்கவும்: ['ஜாவா', 'சி++', 'பைத்தான்', 'ரஸ்ட்']",
"expected": "பைத்தான்"
}

{
"prompt": "நோயாளிக்கு ஒரு வாரத்திற்கு மேலாகத் தொடர் இருமல், காய்ச்சல் மற்றும் மூச்சுத் திணறல் ஆகிய அறிகுறிகள் உள்ளன. இந்த அறிகுறிகளின் தீவிரத்தன்மையை வகைப்படுத்துக. தெரிவுகள்: குறைவு, நடுத்தரம், அதிகம்.",
"expected": "அதிகம்"
